# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Health")]
    public int currentHealth = 100;
    public int maxHealth = 100;

    [Header("Player Currency")]
    public int gold = 0;

    /// <summary>
    /// Applies damage to the player's health.
    /// Health cannot go below 0.
    /// </summary>
    /// <param name="damageAmount">The amount of damage to take.</param>
    public void TakeDamage(int damageAmount)
    {
        if (damageAmount < 0) damageAmount = 0; // Ensure damage is not negative

        currentHealth -= damageAmount;
        if (currentHealth < 0)
        {
            currentHealth = 0;
            // Optionally, add game over logic here
            Debug.Log("Player has been defeated!");
        }
        Debug.Log($"Player took {damageAmount} damage. Current Health: {currentHealth}");
    }

    /// <summary>
    /// Heals the player's health.
    /// Health cannot exceed maxHealth.
    /// </summary>
    /// <param name="healAmount">The amount of health to restore.</param>
    public void Heal(int healAmount)
    {
        if (healAmount < 0) healAmount = 0; // Ensure heal is not negative

        currentHealth += healAmount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }
        Debug.Log($"Player healed {healAmount} health. Current Health: {currentHealth}");
    }

    /// <summary>
    /// Attempts to purchase an item from the shop.
    /// </summary>
    /// <param name="itemCost">The cost of the item.</param>
    /// <returns>True if the purchase was successful, false otherwise.</returns>
    public bool TryPurchaseItem(int itemCost)
    {
        if (itemCost < 0) itemCost = 0; // Ensure cost is not negative

        if (gold >= itemCost)
        {
            gold -= itemCost;
            Debug.Log($"Item purchased for {itemCost} gold. Remaining Gold: {gold}");
            return true;
        }
        else
        {
            Debug.Log($"Not enough gold to purchase item (Cost: {itemCost}, Available: {gold}).");
            return false;
        }
    }

    /// <summary>
    /// Adds gold to the player's currency.
    /// </summary>
    /// <param name="amount">The amount of gold to add.</param>
    public void AddGold(int amount)
    {
        if (amount < 0) amount = 0; // Ensure added amount is not negative

        gold += amount;
        Debug.Log($"Added {amount} gold. Total Gold: {gold}");
    }

    // Example usage (can be called from other scripts or UI buttons)
    void Start()
    {
        // Initial setup
        currentHealth = maxHealth;
        gold = 100; // Starting gold for testing

        Debug.Log($"Game Started! Health: {currentHealth}/{maxHealth}, Gold: {gold}");

        // --- Example Damage and Healing ---
        TakeDamage(20); // Player takes 20 damage
        Heal(10);       // Player heals 10 health
        TakeDamage(90); // Player takes 90 damage (should go to 0)

        // --- Example Shop Purchases ---
        AddGold(50); // Player finds 50 gold
        bool purchasedPotion = TryPurchaseItem(30); // Try to buy a potion
        if (purchasedPotion)
        {
            Debug.Log("Potion acquired!");
            Heal(25); // Use the potion
        }

        bool purchasedSword = TryPurchaseItem(150); // Try to buy an expensive sword
        if (purchasedSword)
        {
            Debug.Log("Sword acquired!");
        }
        else
        {
            Debug.Log("Couldn't buy the sword.");
        }
    }
}